var grSchedules = new GlideRecord('x_153465_discovert_tasker_schedule');
grSchedules.addEncodedQuery('active=true'); 
grSchedules.query();
while(grSchedules.next()){
	// add a single space to force a change
	grSchedules.notes = grSchedules.notes + " ";
	grSchedules.update();
}
